import{_ as e,o as r,c as l,aj as n}from"./chunks/framework.DEEoir6m.js";const p=JSON.parse('{"title":"Pricing","description":"Compare GISPulse tiers — Community (free), Pro, Team and Enterprise. Open-core model AGPL-3.0.","frontmatter":{"title":"Pricing","description":"Compare GISPulse tiers — Community (free), Pro, Team and Enterprise. Open-core model AGPL-3.0."},"headers":[],"relativePath":"en/pricing.md","filePath":"en/pricing.md"}'),i={name:"en/pricing.md"};function a(s,t,d,o,c,y){return r(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h1><p>GISPulse is open-source (AGPL-3.0) with an open-core model. The engine core is free forever.</p><h2 id="early-adopter-offer" tabindex="-1">Early Adopter Offer <a class="header-anchor" href="#early-adopter-offer" aria-label="Permalink to &quot;Early Adopter Offer&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Limited offer — 50 customers</p><p>The first 50 Pro customers get a <strong>49 EUR/month</strong> rate guaranteed for 24 months (then switches to the standard rate or cancellation). 30-day free trial.</p><p><a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">Subscribe / contact us</a></p></div><hr><h2 id="tiers" tabindex="-1">Tiers <a class="header-anchor" href="#tiers" aria-label="Permalink to &quot;Tiers&quot;">​</a></h2><div class="pricing-grid"><div class="pricing-card"><span class="badge-community">Community</span><h3 id="free" tabindex="-1">Free <a class="header-anchor" href="#free" aria-label="Permalink to &quot;Free&quot;">​</a></h3><div class="price">0 EUR<small>/month</small></div><p>AGPL-3.0 license. Open-source.</p><p><strong>Included:</strong></p><ul><li>Full DuckDB engine</li><li>CLI — all commands</li><li>Single-user portal</li><li>Python SDK</li><li>QGIS Plugin</li><li>Docker</li><li>Unlimited local datasets</li></ul><p><strong>Limits:</strong></p><ul><li>1 user</li><li>No REST API key</li><li>No persistent PostGIS</li></ul><p><a href="/gispulse/getting-started/installation">Get started for free</a></p></div><div class="pricing-card featured"><span class="badge-pro">Pro</span><h3 id="_79-eur-month" tabindex="-1">79 EUR/month <a class="header-anchor" href="#_79-eur-month" aria-label="Permalink to &quot;79 EUR/month&quot;">​</a></h3><div class="price">79 EUR<small>/month</small></div><p>790 EUR/year (2 months free)</p><p><strong>Everything in Community, plus:</strong></p><ul><li>Persistent PostGIS</li><li>Hybrid mode DuckDB + PostGIS</li><li>ESB Triggers</li><li>DAG executor</li><li>Visual node editor</li><li>Monitoring / metrics</li><li>Cron pipelines</li><li>Raster capabilities</li><li>Network capabilities</li><li>5 API keys</li><li>50 datasets</li></ul><p><a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">Start 30-day trial</a></p></div><div class="pricing-card"><span class="badge-team">Team</span><h3 id="_299-eur-month" tabindex="-1">299 EUR/month <a class="header-anchor" href="#_299-eur-month" aria-label="Permalink to &quot;299 EUR/month&quot;">​</a></h3><div class="price">299 EUR<small>/month</small></div><p>2,990 EUR/year (2 months free)</p><p><strong>Everything in Pro, plus:</strong></p><ul><li>RBAC (roles and permissions)</li><li>Multi-project</li><li>Priority support 48h</li><li>2 instances</li><li>20 API keys</li><li>Unlimited datasets</li></ul><p><a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">Contact us</a></p></div><div class="pricing-card"><span class="badge-enterprise">Enterprise</span><h3 id="custom-pricing" tabindex="-1">Custom pricing <a class="header-anchor" href="#custom-pricing" aria-label="Permalink to &quot;Custom pricing&quot;">​</a></h3><div class="price">Starting at<small> 1,490 EUR/month</small></div><p><strong>Everything in Team, plus:</strong></p><ul><li>SSO SAML / OIDC</li><li>Horizontal clustering</li><li>White-label</li><li>4h guaranteed SLA</li><li>Custom capabilities</li><li>Unlimited instances</li><li>Unlimited API keys</li><li>Unlimited datasets</li></ul><p><a href="mailto:sales@gispulse.dev" target="_blank" rel="noreferrer">Contact us</a></p></div></div><hr><h2 id="detailed-comparison-table" tabindex="-1">Detailed Comparison Table <a class="header-anchor" href="#detailed-comparison-table" aria-label="Permalink to &quot;Detailed Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th style="text-align:center;">Community</th><th style="text-align:center;">Pro</th><th style="text-align:center;">Team</th><th style="text-align:center;">Enterprise</th></tr></thead><tbody><tr><td><strong>Engine</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>DuckDB (local)</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Persistent PostGIS</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Hybrid mode</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td><strong>Interfaces</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>CLI</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>REST API</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Web portal</td><td style="text-align:center;">single-user</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Python SDK</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>QGIS Plugin</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>ArcGIS Add-in</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Tauri Desktop</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td><strong>Capabilities</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>104 Community capabilities (vector, attributes, classification, stats, topology, 3D pointcloud)</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Raster (<code>rasterio</code>, 6 caps)</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Network (<code>networkx</code>, 6 caps)</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td><code>postgis_sql</code> (parameterised SQL)</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Custom capabilities (entry-points)</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td></tr><tr><td><strong>Orchestration</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>DAG executor</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Cron pipelines</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>ESB Triggers</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Visual node editor</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td><strong>Collaboration</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Multi-user</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>RBAC</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td>Multi-project</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td><td style="text-align:center;">yes</td></tr><tr><td><strong>Security &amp; SLA</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>SSO SAML / OIDC</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td></tr><tr><td>4h SLA</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td></tr><tr><td>White-label</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">yes</td></tr><tr><td>Support</td><td style="text-align:center;">community</td><td style="text-align:center;">community</td><td style="text-align:center;">48h</td><td style="text-align:center;">4h</td></tr><tr><td><strong>Limits</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Users</td><td style="text-align:center;">1</td><td style="text-align:center;">1</td><td style="text-align:center;">unlimited</td><td style="text-align:center;">unlimited</td></tr><tr><td>API keys</td><td style="text-align:center;">0</td><td style="text-align:center;">5</td><td style="text-align:center;">20</td><td style="text-align:center;">unlimited</td></tr><tr><td>Datasets</td><td style="text-align:center;">unlimited (local)</td><td style="text-align:center;">50</td><td style="text-align:center;">unlimited</td><td style="text-align:center;">unlimited</td></tr><tr><td>Instances</td><td style="text-align:center;">1</td><td style="text-align:center;">1</td><td style="text-align:center;">2</td><td style="text-align:center;">unlimited</td></tr></tbody></table><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="is-gispulse-community-really-free" tabindex="-1">Is GISPulse Community really free? <a class="header-anchor" href="#is-gispulse-community-really-free" aria-label="Permalink to &quot;Is GISPulse Community really free?&quot;">​</a></h3><p>Yes, with no time limit and no limit on local data. The code is open under AGPL-3.0 — you can modify and redistribute it under the terms of the license.</p><h3 id="what-is-the-difference-between-agpl-3-0-and-the-pro-license" tabindex="-1">What is the difference between AGPL-3.0 and the Pro license? <a class="header-anchor" href="#what-is-the-difference-between-agpl-3-0-and-the-pro-license" aria-label="Permalink to &quot;What is the difference between AGPL-3.0 and the Pro license?&quot;">​</a></h3><p>Community (AGPL-3.0): if you modify GISPulse and distribute it (including as SaaS), you must publish your modifications. Pro/Team/Enterprise: commercial license allowing proprietary use without publication obligation.</p><h3 id="can-i-upgrade-from-community-to-pro-without-losing-my-data" tabindex="-1">Can I upgrade from Community to Pro without losing my data? <a class="header-anchor" href="#can-i-upgrade-from-community-to-pro-without-losing-my-data" aria-label="Permalink to &quot;Can I upgrade from Community to Pro without losing my data?&quot;">​</a></h3><p>Yes. Local datasets and JSON rules are compatible with all tiers. Migration to PostGIS is assisted by the <code>gispulse portal</code> tool.</p><h3 id="is-there-a-free-trial-for-pro" tabindex="-1">Is there a free trial for Pro? <a class="header-anchor" href="#is-there-a-free-trial-for-pro" aria-label="Permalink to &quot;Is there a free trial for Pro?&quot;">​</a></h3><p>Yes, 30 days trial without credit card. Contact <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact@gispulse.dev</a>.</p><h3 id="what-is-the-early-adopter-offer" tabindex="-1">What is the Early Adopter offer? <a class="header-anchor" href="#what-is-the-early-adopter-offer" aria-label="Permalink to &quot;What is the Early Adopter offer?&quot;">​</a></h3><p>The first 50 Pro customers get a launch rate of 49 EUR/month guaranteed for 24 months. After 24 months: switch to the standard rate (79 EUR/month) or free cancellation. <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">Reserve a spot</a>.</p><h3 id="my-organization-uses-gispulse-as-internal-saas-—-which-tier" tabindex="-1">My organization uses GISPulse as internal SaaS — which tier? <a class="header-anchor" href="#my-organization-uses-gispulse-as-internal-saas-—-which-tier" aria-label="Permalink to &quot;My organization uses GISPulse as internal SaaS — which tier?&quot;">​</a></h3><p>It depends on the number of users and whether you expose GISPulse externally. Contact us for an audit of your use case: <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact@gispulse.dev</a>.</p><h3 id="do-you-offer-discounts-for-ngos-public-sector" tabindex="-1">Do you offer discounts for NGOs / public sector? <a class="header-anchor" href="#do-you-offer-discounts-for-ngos-public-sector" aria-label="Permalink to &quot;Do you offer discounts for NGOs / public sector?&quot;">​</a></h3><p>Yes, upon request. We are committed to geospatial projects serving the public interest.</p><h3 id="does-enterprise-include-on-premise-deployment" tabindex="-1">Does Enterprise include on-premise deployment? <a class="header-anchor" href="#does-enterprise-include-on-premise-deployment" aria-label="Permalink to &quot;Does Enterprise include on-premise deployment?&quot;">​</a></h3><p>Yes. Enterprise is designed for on-premise, air-gapped and multi-tenant deployments.</p>',28)])])}const u=e(i,[["render",a]]);export{p as __pageData,u as default};
